value.string:
{
 "type": "object",
 "description": "Response containing a list of portal types with their metadata",
 "properties": {
 "portalTypes": {
 "type": "array",
 "description": "List of portal types with their metadata in structured format",
 "items": {
 "type": "object",
 "description": "Portal type information",
 "properties": {
 "id": {
 "type": "string",
 "description": "Portal type ID (unique identifier)"
 },
 "allowed": {
 "type": "boolean",
 "description": "Whether it is allowed to query this portal type"
 },
 "restricted": {
 "type": "boolean",
 "description": "Whether the portal type is restricted. For restricted portal types, only some columns can be queried"
 },
 "business_application": {
 "type": "string",
 "description": "The business application (functional area) of the portal type."
 },
 "description": {
 "type": "string",
 "description": "A textual description of the portal type."
 }
 },
 "required": [
 "id",
 "allowed",
 "restricted",
 "description"
 ],
 "additionalProperties": false
 }
 }
 },
 "required": [
 "portalTypes"
 ],
 "additionalProperties": false
 }
